// ============================================================
// FORMAT PROMPT + EXTRAER RESPUESTA
// ============================================================

const webhookData = $input.all();
const incomingMessage = webhookData[0].json;

// Extraer datos del mensaje entrante
const userMessage = incomingMessage.message || '';
const sessionId = incomingMessage.sessionId || 'unknown';
const businessName = incomingMessage.businessName || 'Negocio';
const history = incomingMessage.history || [];

// Construir system prompt con el contexto del negocio
const systemPrompt = `Eres el asistente virtual de ${businessName}. 
Responde de forma amable, natural y concisa. Usa la informacion del negocio para responder.

INFORMACION DEL NEGOCIO:
- Nombre: ${businessName}
- Horario: Lun-Dom 13:00-16:00 y 19:00-23:30
- Direccion: Paseo Maritimo 42, Cala Blanca, Ciutadella, Menorca
- Telefono: +34 971 48 52 10
- Email: info@calablanca.es
- Especialidad: mariscos, caldereta de langosta, arroz negro, pulpo a la brasa
- Precios: €16-€42 por plato principal, menu degustacion €65
- Reservas: hasta 30 dias de antelacion, grupos +8 consultar
- Terraza disponible, vistas al mar, acceso adaptado

PAUTAS:
- Responde en español, tono profesional pero cercano
- Si el visitante pregunta algo que no sabes, dilo con honestidad y ofrece conectarle con una persona
- Si el visitante muestra intencion de compra (pregunta precios, disponibilidad, reservas), ofrece amablemente comprobar disponibilidad
- NO inventes informacion que no tengas`;

// Construir array de mensajes para DeepSeek
const messages = [];

// Agregar historial (ultimos 8 mensajes)
const recentHistory = history.slice(-8);
for (const msg of recentHistory) {
  messages.push({ role: msg.role, content: msg.content });
}

// Agregar mensaje actual si no esta en el historial
if (!recentHistory.length || recentHistory[recentHistory.length - 1].role !== 'user' || recentHistory[recentHistory.length - 1].content !== userMessage) {
  messages.push({ role: 'user', content: userMessage });
}

// Detectar intencion de compra
const leadKeywords = ['precio', 'cuesta', 'cuanto', 'reserva', 'disponibilidad', 'cuando', 'coger', 'apuntar', 'contratar'];
const hasLeadIntent = leadKeywords.some(kw => userMessage.toLowerCase().includes(kw));

return {
  systemPrompt: systemPrompt,
  messages: messages,
  sessionId: sessionId,
  userMessage: userMessage,
  businessName: businessName,
  hasLeadIntent: hasLeadIntent,
  timestamp: new Date().toISOString()
};

// ============================================================
// PROCESAR RESPUESTA DE DEEPSEEK
// ============================================================

const deepseekResponse = $input.all();
const previousData = $('Formatear Prompt').all();
const promptData = previousData[0].json;

// Extraer respuesta del modelo
const choice = deepseekResponse[0].json.choices[0];
const reply = choice.message.content;

// Guardar datos completos para la respuesta y registro
return {
  reply: reply,
  sessionId: promptData.sessionId,
  userMessage: promptData.userMessage,
  businessName: promptData.businessName,
  hasLeadIntent: promptData.hasLeadIntent,
  timestamp: promptData.timestamp,
  model: 'deepseek-chat',
  usage: deepseekResponse[0].json.usage
};

